        const subDir = path.join(sourceDir, 'subdir');
        fs.mkdirSync(subDir);
        fs.writeFileSync(path.join(subDir, 'nested.txt'), 'Nested file content');
    });

    afterEach(function() {
        // Clean up test files
        if (fs.existsSync(testDir)) {
            fs.rmSync(testDir, { recursive: true, force: true });
        }
    });

    it('should create ZipAFolder instance', function() {
        const zipper = new zip_a_folder.ZipAFolder();
        assert(zipper instanceof zip_a_folder.ZipAFolder);
    });

    it('should zip a folder successfully', function(done) {
        const zipper = new zip_a_folder.ZipAFolder();
        const sourceDir = path.join(testDir, 'source');

        zipper.zip(sourceDir, zipPath)
            .then(() => {
                // Verify zip file was created
                assert(fs.existsSync(zipPath));
                assert(fs.statSync(zipPath).size > 0);
                done();
            })
            .catch(done);
    });

    it('should handle empty folder', function(done) {
        const zipper = new zip_a_folder.ZipAFolder();
        const emptyDir = path.join(testDir, 'empty');
        fs.mkdirSync(emptyDir);

        zipper.zip(emptyDir, zipPath)
            .then(() => {
                assert(fs.existsSync(zipPath));
                done();
            })
            .catch(done);
    });

    it('should reject when source folder does not exist', function(done) {
        const zipper = new zip_a_folder.ZipAFolder();
        const nonExistentDir = path.join(testDir, 'nonexistent');

        zipper.zip(nonExistentDir, zipPath)
            .then(() => {
                done(new Error('Should have rejected'));
            })
            .catch((error) => {
                assert(error instanceof Error);
                done();
            });
    });

    it('should reject when destination path is invalid', function(done) {
        const zipper = new zip_a_folder.ZipAFolder();
        const sourceDir = path.join(testDir, 'source');
        const invalidPath = path.join('/invalid/path/that/does/not/exist', 'test.zip');

        zipper.zip(sourceDir, invalidPath)
            .then(() => {
                done(new Error('Should have rejected'));
            })
            .catch((error) => {
                assert(error instanceof Error);
                done();
            });
    });
});
